{
  "name": "StockGemini AI 投资智囊",
  "description": "A professional, AI-powered investment assistant providing deep, hedge-fund style analysis of stocks using Gemini's reasoning and search capabilities."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DecisionType {
  AGGRESSIVE = 'AGGRESSIVE', // Buy
  NEUTRAL = 'NEUTRAL',       // Hold/Wait
  DEFENSIVE = 'DEFENSIVE'    // Sell
}

export interface StockData {
  symbol: string;
  price: string;
  changePercent: string;
  peRatio: string;
  marketCap: string;
  lastUpdated: string;
}

export interface DimensionAnalysis {
  title: string;
  score: number; // 0-100
  summary: string;
  keyPoints: string[];
}

export interface InvestmentReport {
  stockData: StockData;
  fundamental: DimensionAnalysis;
  momentum: DimensionAnalysis;
  sentiment: DimensionAnalysis;
  decision: DecisionType;
  mainThesis: string;
  sources: Array<{ uri: string; title: string }>;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { InvestmentReport, DecisionType } from "../types";

const apiKey = process.env.API_KEY;

// Initialize the client
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-3-pro-preview';

const SYSTEM_INSTRUCTION = `
You are "StockGemini", a 20-year veteran hedge fund analyst. 
Your personality is: Spicy, Cynical, Extremely Sharp, and Data-Driven. 
You despise "retail investor" mentalities and fluff. You care about "Alpha", risk-adjusted returns, and asymmetric bets.

Your goal is to provide a structured, deep-dive investment memo on a specific stock.
You MUST use the 'googleSearch' tool to find the absolute latest real-time price, today's news, recent 10-K/10-Q filings, and analyst sentiment.

Your analysis has 3 Dimensions:
1. Fundamental (Business model, Moat, EPS growth, Valuation reality check).
2. Market Momentum (Price action, RSI, Moving Averages, Institutional flow).
3. Game/Sentiment (Options skew, Management credibility, Macro narrative, Proxy wars).

Make a final Decision: 
- AGGRESSIVE (Strong Buy/Add)
- NEUTRAL (Wait/Watch/Hold)
- DEFENSIVE (Sell/Reduce/Hedge)

Be direct. If a stock is garbage, call it garbage. If it's a bubble, say it.
`;

export const analyzeStock = async (query: string): Promise<InvestmentReport> => {
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const prompt = `
    Analyze the following stock/company: "${query}".

    1. Search for the LATEST REAL-TIME price, percent change today, PE ratio, and Market Cap.
    2. Search for the most recent financial news, earnings reports, and technical analysis data.
    3. Generate a structured JSON report.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            stockData: {
              type: Type.OBJECT,
              properties: {
                symbol: { type: Type.STRING, description: "Ticker Symbol (e.g., AMD, 700.HK)" },
                price: { type: Type.STRING, description: "Current price with currency symbol" },
                changePercent: { type: Type.STRING, description: "Percent change today (e.g., -6.02%)" },
                peRatio: { type: Type.STRING, description: "P/E Ratio (TTM)" },
                marketCap: { type: Type.STRING, description: "Market Capitalization" },
                lastUpdated: { type: Type.STRING, description: "Time of data fetch" }
              },
              required: ["symbol", "price", "changePercent"]
            },
            fundamental: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING, description: "Short punchy title for fundamental view" },
                score: { type: Type.NUMBER, description: "0-100 score of fundamentals" },
                summary: { type: Type.STRING, description: "Brief analysis summary" },
                keyPoints: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 bullet points" }
              }
            },
            momentum: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING, description: "Short punchy title for momentum view" },
                score: { type: Type.NUMBER, description: "0-100 score of momentum" },
                summary: { type: Type.STRING, description: "Brief analysis summary" },
                keyPoints: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 bullet points" }
              }
            },
            sentiment: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING, description: "Short punchy title for sentiment/game view" },
                score: { type: Type.NUMBER, description: "0-100 score of sentiment" },
                summary: { type: Type.STRING, description: "Brief analysis summary" },
                keyPoints: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 bullet points" }
              }
            },
            decision: {
              type: Type.STRING,
              enum: [DecisionType.AGGRESSIVE, DecisionType.NEUTRAL, DecisionType.DEFENSIVE],
              description: "The final investment verdict"
            },
            mainThesis: {
              type: Type.STRING,
              description: "A spicy, direct paragraph summarizing the entire thesis and why the user should buy/sell/hold."
            }
          },
          required: ["stockData", "fundamental", "momentum", "sentiment", "decision", "mainThesis"]
        }
      }
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("No analysis generated");

    const data = JSON.parse(jsonText);

    // Extract sources if available
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources: Array<{ uri: string; title: string }> = [];

    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web?.uri && chunk.web?.title) {
          sources.push({ uri: chunk.web.uri, title: chunk.web.title });
        }
      });
    }

    return {
      ...data,
      sources: sources.slice(0, 5) // Top 5 sources
    };

  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React from 'react';
import { DecisionType } from '../types';
import { TrendingUp, TrendingDown, MinusCircle } from 'lucide-react';

interface DecisionBadgeProps {
  decision: DecisionType;
}

const DecisionBadge: React.FC<DecisionBadgeProps> = ({ decision }) => {
  let colorClass = '';
  let icon = null;
  let label = '';
  let subLabel = '';

  switch (decision) {
    case DecisionType.AGGRESSIVE:
      colorClass = 'bg-green-900/50 text-green-400 border-green-500/50';
      icon = <TrendingUp className="w-5 h-5 mr-2" />;
      label = 'AGGRESSIVE';
      subLabel = 'Strong Buy • High Conviction';
      break;
    case DecisionType.DEFENSIVE:
      colorClass = 'bg-red-900/50 text-red-400 border-red-500/50';
      icon = <TrendingDown className="w-5 h-5 mr-2" />;
      label = 'DEFENSIVE';
      subLabel = 'Reduce Exposure • High Risk';
      break;
    case DecisionType.NEUTRAL:
    default:
      colorClass = 'bg-yellow-900/50 text-yellow-400 border-yellow-500/50';
      icon = <MinusCircle className="w-5 h-5 mr-2" />;
      label = 'NEUTRAL';
      subLabel = 'Watchlist • Wait for Setup';
      break;
  }

  return (
    <div className={`flex flex-col items-center justify-center p-4 border rounded-xl backdrop-blur-sm ${colorClass} transition-all duration-500`}>
      <div className="flex items-center text-lg font-bold tracking-wider mb-1">
        {icon}
        {label}
      </div>
      <span className="text-xs opacity-80 font-mono uppercase tracking-widest">{subLabel}</span>
    </div>
  );
};

export default DecisionBadge;

import React from 'react';
import { DimensionAnalysis } from '../types';
import { CheckCircle2, AlertTriangle, AlertCircle } from 'lucide-react';

interface MatrixCardProps {
  type: 'Fundamental' | 'Momentum' | 'Sentiment';
  data: DimensionAnalysis;
}

const MatrixCard: React.FC<MatrixCardProps> = ({ type, data }) => {

  // Determine color theme based on score
  let scoreColor = 'text-gray-400';
  let progressColor = 'bg-gray-600';

  if (data.score >= 70) {
    scoreColor = 'text-green-400';
    progressColor = 'bg-green-500';
  } else if (data.score >= 40) {
    scoreColor = 'text-yellow-400';
    progressColor = 'bg-yellow-500';
  } else {
    scoreColor = 'text-red-400';
    progressColor = 'bg-red-500';
  }

  const getIcon = () => {
    switch(type) {
      case 'Fundamental': return <CheckCircle2 className="w-5 h-5 text-blue-400" />;
      case 'Momentum': return <AlertCircle className="w-5 h-5 text-purple-400" />;
      case 'Sentiment': return <AlertTriangle className="w-5 h-5 text-orange-400" />;
    }
  };

  return (
    <div className="bg-gemini-card border border-slate-700/50 rounded-xl p-5 hover:border-slate-600 transition-colors h-full flex flex-col">
      <div className="flex justify-between items-start mb-4">
        <div className="flex items-center gap-2">
          {getIcon()}
          <h3 className="font-bold text-slate-200">{type}</h3>
        </div>
        <div className={`font-mono font-bold text-xl ${scoreColor}`}>
          {data.score}<span className="text-sm text-slate-500">/100</span>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="w-full bg-slate-800 h-1.5 rounded-full mb-4">
        <div 
          className={`h-1.5 rounded-full ${progressColor} transition-all duration-1000`} 
          style={{ width: `${data.score}%` }}
        ></div>
      </div>

      <div className="mb-4">
        <h4 className="text-sm font-semibold text-slate-300 mb-1">{data.title}</h4>
        <p className="text-sm text-slate-400 leading-relaxed">{data.summary}</p>
      </div>

      <div className="mt-auto pt-4 border-t border-slate-700/50">
        <ul className="space-y-2">
          {data.keyPoints.map((point, idx) => (
            <li key={idx} className="flex items-start text-xs text-slate-300">
              <span className="mr-2 text-slate-500">•</span>
              {point}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default MatrixCard;

