import React, { useState } from 'react';
import Header from './components/Header';
import MatrixCard from './components/MatrixCard';
import DecisionBadge from './components/DecisionBadge';
import { analyzeStock } from './services/geminiService';
import { InvestmentReport } from './types';
import { Search, Loader2, ArrowRight, ExternalLink, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [report, setReport] = useState<InvestmentReport | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setError(null);
    setReport(null);

    try {
      const data = await analyzeStock(query);
      setReport(data);
    } catch (err) {
      setError("Failed to generate analysis. Please try again or check your API key.");
    } finally {
      setLoading(false);
    }
  };

  const isPositiveChange = report?.stockData.changePercent.startsWith('+') || 
                           (report && !report.stockData.changePercent.startsWith('-'));

  return (
    <div className="min-h-screen bg-gemini-dark text-slate-200 font-sans selection:bg-gemini-accent selection:text-white">
      <Header />

      <main className="max-w-7xl mx-auto px-4 md:px-8 py-8 md:py-12">

        {/* Search Section */}
        <section className="mb-12 max-w-2xl mx-auto text-center">
          <h2 className="text-3xl md:text-4xl font-bold mb-6 text-white">
            Where is the <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-purple-400">Alpha</span> hiding today?
          </h2>

          <form onSubmit={handleSearch} className="relative group">
            <div className="absolute inset-y-0 left-0 flex items-center pl-4 pointer-events-none">
              <Search className="w-5 h-5 text-slate-500 group-focus-within:text-gemini-accent transition-colors" />
            </div>
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Enter ticker (e.g., AMD, 700.HK) or name..."
              className="w-full pl-12 pr-4 py-4 bg-slate-800/50 border border-slate-700 rounded-2xl focus:ring-2 focus:ring-gemini-accent focus:border-transparent outline-none text-lg text-white placeholder-slate-500 transition-all shadow-lg"
            />
            <button 
              type="submit" 
              disabled={loading || !query.trim()}
              className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-500 text-white px-6 rounded-xl font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
            >
              {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <ArrowRight className="w-5 h-5" />}
            </button>
          </form>
          <p className="mt-4 text-sm text-slate-500">
            Supports US, HK, and CN markets. Data grounded by Google Search.
          </p>
        </section>

        {/* Error State */}
        {error && (
          <div className="max-w-2xl mx-auto bg-red-900/20 border border-red-500/50 text-red-200 p-4 rounded-xl flex items-center gap-3 mb-8">
            <AlertTriangle className="w-5 h-5 flex-shrink-0" />
            <p>{error}</p>
          </div>
        )}

        {/* Loading State Skeleton */}
        {loading && (
          <div className="max-w-6xl mx-auto animate-pulse">
            <div className="h-24 bg-slate-800 rounded-xl mb-6 w-full"></div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
              <div className="h-64 bg-slate-800 rounded-xl"></div>
              <div className="h-64 bg-slate-800 rounded-xl"></div>
              <div className="h-64 bg-slate-800 rounded-xl"></div>
            </div>
            <div className="h-32 bg-slate-800 rounded-xl w-full"></div>
          </div>
        )}

        {/* Results Section */}
        {report && !loading && (
          <div className="animate-fade-in-up max-w-6xl mx-auto space-y-8">

            {/* 1. Real-time Dashboard Bar */}
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
              <div className="lg:col-span-3 bg-gemini-card border border-slate-700 rounded-xl p-6 flex flex-col md:flex-row md:items-center justify-between gap-6 shadow-2xl">
                <div>
                  <h2 className="text-3xl font-bold text-white tracking-tight">{report.stockData.symbol}</h2>
                  <p className="text-sm text-slate-400 mt-1">Real-time Snapshot</p>
                </div>

                <div className="flex flex-wrap gap-8 items-end">
                  <div>
                    <span className="block text-xs text-slate-500 font-mono uppercase">Price</span>
                    <span className="text-3xl font-mono font-bold text-white">{report.stockData.price}</span>
                  </div>
                  <div>
                    <span className="block text-xs text-slate-500 font-mono uppercase">Day Change</span>
                    <span className={`text-xl font-mono font-bold ${isPositiveChange ? 'text-green-400' : 'text-red-400'}`}>
                      {report.stockData.changePercent}
                    </span>
                  </div>
                  <div className="hidden md:block w-px h-12 bg-slate-700 mx-2"></div>
                  <div>
                    <span className="block text-xs text-slate-500 font-mono uppercase">P/E Ratio</span>
                    <span className="text-xl font-mono text-slate-200">{report.stockData.peRatio}</span>
                  </div>
                  <div>
                    <span className="block text-xs text-slate-500 font-mono uppercase">Mkt Cap</span>
                    <span className="text-xl font-mono text-slate-200">{report.stockData.marketCap}</span>
                  </div>
                </div>
              </div>

              {/* Decision Badge */}
              <div className="lg:col-span-1">
                <DecisionBadge decision={report.decision} />
              </div>
            </div>

            {/* 2. The Thesis (Chat bubble style) */}
            <div className="bg-gradient-to-r from-slate-800 to-slate-900 border border-slate-700/50 rounded-xl p-6 md:p-8 relative overflow-hidden">
               <div className="absolute top-0 left-0 w-1 h-full bg-gemini-gold"></div>
               <h3 className="text-gemini-gold font-mono text-xs tracking-widest uppercase mb-3">Analyst Thesis (Spicy Mode)</h3>
               <p className="text-lg md:text-xl leading-relaxed font-light text-slate-200">
                 "{report.mainThesis}"
               </p>
            </div>

            {/* 3. 3D Assessment Matrix */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <MatrixCard type="Fundamental" data={report.fundamental} />
              <MatrixCard type="Momentum" data={report.momentum} />
              <MatrixCard type="Sentiment" data={report.sentiment} />
            </div>

            {/* 4. Sources / Grounding */}
            <div className="pt-8 border-t border-slate-800">
               <h4 className="text-sm font-semibold text-slate-500 mb-4">Live Data Sources</h4>
               <div className="flex flex-wrap gap-3">
                 {report.sources.length > 0 ? (
                   report.sources.map((source, idx) => (
                     <a 
                       key={idx}
                       href={source.uri}
                       target="_blank"
                       rel="noopener noreferrer"
                       className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 rounded-lg text-xs text-slate-400 transition-colors border border-slate-700"
                     >
                       <ExternalLink className="w-3 h-3" />
                       <span className="max-w-[200px] truncate">{source.title}</span>
                     </a>
                   ))
                 ) : (
                   <span className="text-xs text-slate-600 italic">Data synthesized from internal knowledge base.</span>
                 )}
               </div>
            </div>

          </div>
        )}
      </main>
    </div>
  );
};

export default App;

